/**
 * @fluxstack/plugin-sdk/env
 *
 * Lightweight environment variable loader for plugins.
 * Self-contained — no dependency on FluxStack internals.
 *
 * @example
 * ```ts
 * import { env } from '@fluxstack/plugin-sdk/env'
 *
 * const port = env.get('PORT', 3000)       // number
 * const debug = env.get('DEBUG', false)     // boolean
 * const tags = env.get('TAGS', ['api'])     // string[]
 * ```
 */

class EnvLoader {
  private cache = new Map<string, unknown>()

  private getEnvSource(): Record<string, string | undefined> {
    const g = globalThis as unknown as Record<string, Record<string, unknown> | undefined>

    // Bun.env first
    const bun = g['Bun'] as Record<string, unknown> | undefined
    if (bun?.['env']) return bun['env'] as Record<string, string | undefined>

    // process.env fallback
    const proc = g['process'] as Record<string, unknown> | undefined
    if (proc?.['env']) return proc['env'] as Record<string, string | undefined>

    return {}
  }

  get<T>(key: string, defaultValue?: T): T {
    const cacheKey = `${key}:${typeof defaultValue}`
    if (this.cache.has(cacheKey)) return this.cache.get(cacheKey) as T

    const source = this.getEnvSource()
    const raw = source[key]

    if (!raw || raw === '') {
      this.cache.set(cacheKey, defaultValue as T)
      return defaultValue as T
    }

    let result: unknown = raw

    if (typeof defaultValue === 'number') {
      const n = Number(raw)
      result = isNaN(n) ? defaultValue : n
    } else if (typeof defaultValue === 'boolean') {
      result = ['true', '1', 'yes', 'on'].includes(raw.toLowerCase())
    } else if (Array.isArray(defaultValue)) {
      result = raw.split(',').map(v => v.trim()).filter(Boolean)
    } else if (typeof defaultValue === 'object' && defaultValue !== null) {
      try { result = JSON.parse(raw) } catch { result = defaultValue }
    }

    this.cache.set(cacheKey, result)
    return result as T
  }

  has(key: string): boolean {
    const source = this.getEnvSource()
    const v = source[key]
    return v !== undefined && v !== ''
  }

  all(): Record<string, string> {
    const source = this.getEnvSource()
    const out: Record<string, string> = {}
    for (const [k, v] of Object.entries(source)) {
      if (v !== undefined && v !== '') out[k] = v
    }
    return out
  }

  clearCache(): void {
    this.cache.clear()
  }
}

const loader = new EnvLoader()

export const env = {
  get: <T>(key: string, defaultValue?: T): T => loader.get(key, defaultValue),
  has: (key: string): boolean => loader.has(key),
  all: (): Record<string, string> => loader.all(),
  clearCache: (): void => loader.clearCache(),
}

export default env
